package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testIsEscaping_whenEscapeIsNull_returnsFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // use reflection to set private final field escape to null
        Field escapeField = CSVFormat.class.getDeclaredField("escape");
        escapeField.setAccessible(true);

        // remove final modifier
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(escapeField, escapeField.getModifiers() & ~Modifier.FINAL);

        // Since CSVFormat is immutable, setting the field on DEFAULT instance will not affect behavior,
        // so create a new CSVFormat instance with escape null via reflection of constructor or clone.
        // Instead, create a new instance via constructor with escape=null

        // Find the constructor
        java.lang.reflect.Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, CSVFormat.Quote.class, Character.class, Character.class,
                boolean.class, boolean.class, String.class, String.class, String[].class, boolean.class);
        constructor.setAccessible(true);

        CSVFormat formatWithNullEscape = constructor.newInstance(
                format.getDelimiter(),
                format.getQuoteChar(),
                format.getQuotePolicy(),
                format.getCommentStart(),
                null, // escape set to null
                format.getIgnoreSurroundingSpaces(),
                format.getIgnoreEmptyLines(),
                format.getRecordSeparator(),
                format.getNullString(),
                format.getHeader(),
                format.getSkipHeaderRecord()
        );

        assertFalse(formatWithNullEscape.isEscaping());
    }

    @Test
    void testIsEscaping_whenEscapeIsNonNull_returnsTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        assertTrue(format.isEscaping());
    }
}
